// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef, useMemo } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}

function useComponent(props: Props) {
  const normalizedUnit = props.unit === 'F' ? 'F' : 'C';

  const currentCondition = useMemo(() => props.condition || 'Weather', [props.condition]);
  const forecastItems = useMemo(() => {
    return props.forecast ?? [];
  }, [props.forecast]);

  const formattedTemperature = useMemo(() => `${props.temperature}°${normalizedUnit}`, [props.temperature, normalizedUnit]);
  const humidityLabel = useMemo(() => `${props.humidity}%`, [props.humidity]);
  const windLabel = useMemo(() => `${props.windSpeed} km/h`, [props.windSpeed]);

  const getConditionIcon = useCallback((condition: string) => {
    const normalized = condition.toLowerCase();
    if (normalized.includes('rain') || normalized.includes('drizzle') || normalized.includes('storm')) return '🌧️';
    if (normalized.includes('cloud') || normalized.includes('overcast') || normalized.includes('fog') || normalized.includes('mist')) return '☁️';
    if (normalized.includes('snow') || normalized.includes('sleet') || normalized.includes('hail')) return '❄️';
    if (normalized.includes('wind')) return '💨';
    if (normalized.includes('thunder')) return '⛈️';
    if (normalized.includes('clear') || normalized.includes('sun') || normalized.includes('bright')) return '☀️';
    return '🌤️';
  }, []);

  const currentIcon = getConditionIcon(currentCondition);

  return {
    normalizedUnit,
    currentCondition,
    forecastItems,
    formattedTemperature,
    humidityLabel,
    windLabel,
    currentIcon,
    getConditionIcon,
  };
}
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="lg" padding={24}>
      <Card shadow="md" padding={24} radius="xl">
        <Stack gap={24}>
          <Stack gap={12}>
            <Row align="center" justify="between" wrap>
              <Stack gap={4}>
                <Text variant="overline" color="var(--ggui-color-primary-700, #0369a1)">
                  {props.city}
                </Text>
                <Heading level={2}>
                  Weather Now
                </Heading>
              </Stack>
            </Row>

            <Row align="center" gap={16} wrap>
              <Text
                size="4xl"
                weight="bold"
                color="var(--ggui-color-onSurface, #18181b)"
              >
                {state.formattedTemperature}
              </Text>
              <Stack gap={4} align="start">
                <Text variant="bodyLarge">
                  {state.currentIcon} {state.currentCondition}
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Humidity {state.humidityLabel} · Wind {state.windLabel}
                </Text>
              </Stack>
            </Row>

            <Row gap={16} wrap>
              <Card padding={16} shadow="none" border radius="lg">
                <Stack gap={4}>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
                  <Text variant="bodyLarge" weight="semibold">{state.humidityLabel}</Text>
                </Stack>
              </Card>
              <Card padding={16} shadow="none" border radius="lg">
                <Stack gap={4}>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind Speed</Text>
                  <Text variant="bodyLarge" weight="semibold">{state.windLabel}</Text>
                </Stack>
              </Card>
            </Row>
          </Stack>

          <Divider />

          <Stack gap={16}>
            <Row align="center" justify="between" wrap>
              <Heading level={4}>5-Day Forecast</Heading>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Forecast from props
              </Text>
            </Row>

            <Row gap={12} wrap>
              {state.forecastItems.map((item, index) => (
                <Card
                  key={`${item.day || 'day'}-${index}`}`
                  padding={16}
                  shadow="sm"
                  border
                  radius="lg"
                >
                  <Stack gap={8} align="center">
                    <Text variant="label">{item.day || `Day ${index + 1}`}</Text>
                    <Text size="2xl" is="div">{item.icon || ''}</Text>
                    <Text variant="bodySmall" weight="semibold">
                      {item.high}°{state.normalizedUnit} / {item.low}°{state.normalizedUnit}
                    </Text>
                  </Stack>
                </Card>
              ))}
            </Row>

            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              All data shown comes directly from props.
            </Text>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
  onSubmit: (payload: ActionSubmitPayload) => void;
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };

function useComponent(props: Props) {
  const submit = useCallback((payload: ActionSubmitPayload) => {
    props.onSubmit(payload);
  }, [props]);

  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState<number>(0);
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [nameTouched, setNameTouched] = useState(false);
  const [emailTouched, setEmailTouched] = useState(false);

  const emailIsValid = useCallback((value: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value), []);
  const normalizeFeatureSelection = useCallback((selected: string[]) => {
    const selectedSet = new Set(selected);
    return props.featureOptions.filter((feature) => selectedSet.has(feature));
  }, [props.featureOptions]);

  const nameError = nameTouched && !name.trim() ? 'Name is required' : '';
  const emailError = emailTouched && !email.trim() ? 'Email is required' : emailTouched && !emailIsValid(email) ? 'Enter a valid email address' : '';
  const step1Valid = !!name.trim() && emailIsValid(email);
  const step2Valid = satisfaction >= 1 && satisfaction <= 5;
  const step3Valid = true;
  const commentsCount = comments.length;
  const reviewReady = step1Valid && step2Valid && step3Valid;
  const canGoNext = (step === 1 && step1Valid) || (step === 2 && step2Valid) || (step === 3 && step3Valid);
  const canSubmit = step === 4 && reviewReady;

  const selectedFeatureLabels = props.featureOptions.filter((feature) => features.includes(feature));
  const satisfactionLabel = satisfaction > 0 && satisfaction <= props.satisfactionLabels.length ? props.satisfactionLabels[satisfaction - 1] : 'Not selected';
  const commentsPreview = comments || 'No comments provided';
  const selectedFeatureCount = selectedFeatureLabels.length;

  const reviewItems = [
    { label: 'Name', value: name.trim() || '—' },
    { label: 'Email', value: email.trim() || '—' },
    { label: 'Satisfaction', value: satisfactionLabel },
    { label: 'Features', value: selectedFeatureLabels.length ? selectedFeatureLabels.join(', ') : 'None selected' },
    { label: 'Comments', value: commentsPreview },
  ];

  const currentStepLabel = step === 1 ? 'Your details' : step === 2 ? 'Satisfaction' : step === 3 ? 'Feature interests' : 'Final review';

  const nextStep = useCallback(() => {
    if (step === 1) {
      setNameTouched(true);
      setEmailTouched(true);
    }
    if (step === 1 && !step1Valid) return;
    if (step === 2 && !step2Valid) return;
    if (step === 3 && !step3Valid) return;
    if (step < 4) {
      setStep(step + 1);
    }
  }, [step, step1Valid, step2Valid, step3Valid]);

  const prevStep = useCallback(() => {
    setStep((current) => Math.max(1, current - 1));
  }, []);

  const toggleFeature = useCallback((feature: string) => {
    setFeatures((current) => {
      const next = current.includes(feature) ? current.filter((item) => item !== feature) : [...current, feature];
      return normalizeFeatureSelection(next);
    });
  }, [normalizeFeatureSelection]);

  const handleSubmit = useCallback(() => {
    if (!reviewReady) return;
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction,
      features: normalizeFeatureSelection(features),
      comments,
    });
  }, [reviewReady, submit, name, email, satisfaction, features, comments, normalizeFeatureSelection]);

  return {
    submit,
    step,
    setStep,
    name,
    setName,
    email,
    setEmail,
    satisfaction,
    setSatisfaction,
    features,
    setFeatures,
    comments,
    setComments,
    nameTouched,
    setNameTouched,
    emailTouched,
    setEmailTouched,
    emailIsValid,
    nameError,
    emailError,
    step1Valid,
    step2Valid,
    step3Valid,
    commentsCount,
    canGoNext,
    canSubmit,
    selectedFeatureLabels,
    selectedFeatureCount,
    satisfactionLabel,
    reviewReady,
    reviewItems,
    commentsPreview,
    currentStepLabel,
    showReviewStep: step === 4,
    nextStep,
    prevStep,
    toggleFeature,
    handleSubmit,
  };



export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={24}>
        <Card padding={24} shadow="sm" radius="lg">
          <Stack gap={16}>
            <Heading level={2}>Multi-step survey</Heading>
            <Stack gap={8}>
                <Row justify="between" align="center">
                  <Text variant="label">Step {state.step} of 4</Text>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {state.currentStepLabel}
                  </Text>
                </Row>
                <Progress value={state.step} max={4} showLabel />
          </Stack>
        </Card>

        <Card padding={24} shadow="sm" radius="lg">
          <Stack gap={24}>
            {state.step === 1 && (
              <Stack gap={16}>
                <Heading level={3}>Tell us about you</Heading>
                <Input
                  label="Name"
                  value={state.name}
                  onChange={(value) => { state.setName(value); if (!state.nameTouched) state.setNameTouched(true); }}
                  required
                  error={state.nameError}
                  placeholder="Enter your name"
                />
                <Input
                  label="Email"
                  type="email"
                  value={state.email}
                  onChange={(value) => { state.setEmail(value); if (!state.emailTouched) state.setEmailTouched(true); }}
                  required
                  error={state.emailError}
                  placeholder="you@example.com"
                />
              </Stack>
            )}

            {state.step === 2 && (
              <Stack gap={16}>
                <Heading level={3}>How satisfied are you?</Heading>
                <RadioGroup
                  label="Satisfaction rating"
                  value={state.satisfaction > 0 ? String(state.satisfaction) : ''}
                  onChange={(value) => state.setSatisfaction(Number(value))}
                  options={props.satisfactionLabels.map((label, index) => ({ value: String(index + 1), label }))}
                />
              </Stack>
            )}

            {state.step === 3 && (
              <Stack gap={16}>
                <Heading level={3}>Which features interest you?</Heading>
                <Stack gap={12}>
                  {props.featureOptions.map((feature) => (
                    <Checkbox
                      key={feature}
                      label={feature}
                      checked={state.features.includes(feature)}
                      onChange={() => state.toggleFeature(feature)}
                    />
                  ))}
                </Stack>
              </Stack>
            )}

            {state.step === 4 && (
              <Stack gap={16}>
                <Heading level={3}>Final review</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  This step is read-only so you can confirm all answers before submission.
                </Text>
                <Card padding={16} shadow="none" radius="md" border>
                  <Stack gap={12}>
                    <Heading level={4}>Review before submission</Heading>
                    <Text variant="bodySmall">Please confirm your responses below before submitting.</Text>
                    <Divider margin={8} />
                    {state.reviewItems.map((item) => (
                      <Stack key={item.label} gap={4}>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">{item.label}</Text>
                        <Text variant="bodySmall">{item.value}</Text>
                      </Stack>
                    ))}
                    <Divider margin={8} />
                    <Stack gap={8}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Comments</Text>
                      <Text variant="bodySmall">{state.commentsPreview}</Text>
                    </Stack>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Use Back to make changes before submitting.
                    </Text>
                  </Stack>
                </Card>
              </Stack>
            )}
            )}

            <Divider />

            <Row justify="between" align="center">
              <Button variant="secondary" onClick={state.prevStep} disabled={state.step === 1}>Back</Button>
              {state.step < 4 ? (
                <Button variant="primary" onClick={state.nextStep} disabled={!state.canGoNext}>Next</Button>
              ) : (
                <Button variant="primary" onClick={state.handleSubmit} disabled={!state.canSubmit}>Submit</Button>
              )}
            </Row>
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef, useEffect } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };

type Task = {
  id: string;
  title: string;
  priority: 'low' | 'medium' | 'high';
  assignee: string;
  column: string;
  dueDate?: string;
};

function normalizeTask(task: Props['tasks'][number], fallbackColumn: string, index: number): Task {
  return {
    id: task.id ?? `task-${index}`,
    title: task.title ?? 'Untitled task',
    priority: task.priority ?? 'medium',
    assignee: task.assignee ?? '',
    column: task.column ?? fallbackColumn,
    dueDate: task.dueDate,
  };
}

function useComponent(props: Props) {
  const safeColumns = Array.isArray(props.columns) ? props.columns : [];
  const safeTasks = Array.isArray(props.tasks) ? props.tasks : [];
  const initialColumns = safeColumns.length
    ? safeColumns.map((column, index) => ({ id: column.id ?? `column-${index}`, name: column.name ?? `Column ${index + 1}` }))
    : [
        { id: 'todo', name: 'To Do' },
        { id: 'in-progress', name: 'In Progress' },
        { id: 'done', name: 'Done' },
      ];
  const toDoColumnId = initialColumns[0]?.id ?? 'todo';
  const doneColumnId = initialColumns[2]?.id ?? 'done';
  const [tasks, setTasks] = useState<Task[]>(() => safeTasks.map((task, index) => normalizeTask(task, toDoColumnId, index)));
  const [newTaskColumn, setNewTaskColumn] = useState<string | null>(null);
  const [draftTitle, setDraftTitle] = useState('');
  const [draftPriority, setDraftPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [columnsState, setColumnsState] = useState(initialColumns);
  const [lastStreamRevision, setLastStreamRevision] = useState(0);
  const [handledStreamActions, setHandledStreamActions] = useState<Record<string, number>>({});
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');

  const syncTasks = useCallback((sourceTasks: Task[], events: StreamTaskChanged[]) => {
    const latestById = new Map<string, Task>();
    for (const task of sourceTasks) {
      latestById.set(task.id, task);
    }

    for (const payload of events) {
      const action = payload.action ?? 'edit';
      const incoming = payload.task;
      if (!incoming?.id) continue;

      const existing = latestById.get(incoming.id);
      const normalizedIncoming: Task = {
        id: incoming.id,
        title: incoming.title ?? existing?.title ?? 'Untitled task',
        priority: incoming.priority ?? existing?.priority ?? 'medium',
        assignee: incoming.assignee ?? existing?.assignee ?? '',
        column: incoming.column ?? existing?.column ?? toDoColumnId,
        dueDate: incoming.dueDate ?? existing?.dueDate,
      };

      if (action === 'delete') {
        latestById.delete(incoming.id);
        continue;
      }

      if (action === 'move') {
        latestById.set(incoming.id, {
          ...normalizedIncoming,
          column: incoming.column ?? existing?.column ?? toDoColumnId,
        });
        continue;
      }

      if (action === 'create') {
        latestById.set(incoming.id, {
          ...normalizedIncoming,
          column: incoming.column ?? toDoColumnId,
        });
        continue;
      }

      latestById.set(incoming.id, normalizedIncoming);
    }

    return Array.from(latestById.values());
  }, [toDoColumnId]);

  const applyStreamEvent = useCallback((event: StreamTaskChanged | StreamTaskChanged[]) => {
    const events = Array.isArray(event) ? event : [event];
    setLastStreamRevision((revision) => revision + 1);
    setTasks((current) => syncTasks(current, events));
    setHandledStreamActions((current) => {
      const next = { ...current };
      for (const payload of events) {
        const id = payload.task?.id;
        if (!id) continue;
        next[id] = (next[id] ?? 0) + 1;
      }
      return next;
    });
  }, [syncTasks]);

  useEffect(() => {
    setColumnsState(initialColumns);
  }, [initialColumns]);

  useEffect(() => {
    setTasks((current) => {
      const merged = syncTasks(current, safeTasks.map((task, index) => ({ action: 'edit' as const, task: normalizeTask(task, toDoColumnId, index) })));
      return merged;
    });
  }, [safeTasks, syncTasks, toDoColumnId]);

  const taskChanged = useStream<StreamTaskChanged>('taskChanged');

  useEffect(() => {
    if (taskChanged.latest) {
      applyStreamEvent(taskChanged.latest);
    }
  }, [applyStreamEvent, taskChanged.latest]);

  useEffect(() => {
    if (typeof window === 'undefined') return;
    const handler = (event: Event) => {
      const custom = event as CustomEvent<StreamTaskChanged | StreamTaskChanged[]>;
      if (!custom.detail) return;
      applyStreamEvent(custom.detail);
    };
    window.addEventListener('taskChanged', handler as EventListener);
    return () => window.removeEventListener('taskChanged', handler as EventListener);
  }, [applyStreamEvent]);

  const columnOrder = columnsState && columnsState.length ? columnsState : initialColumns;
  const getTaskById = useCallback((taskId: string) => tasks.find((task) => task.id === taskId), [tasks]);
  const totalTasks = tasks.length;
  const completedTasks = tasks.filter((task) => task.column === doneColumnId).length;

  const moveTask = useCallback((taskId: string, nextColumn: string) => {
    const destination = columnOrder.some((column) => column.id === nextColumn) ? nextColumn : toDoColumnId;
    setTasks((current) => current.map((task) => (task.id === taskId ? { ...task, column: destination } : task)));
    taskUpdate({ action: 'move', taskId, data: { column: destination } });
  }, [columnOrder, taskUpdate, toDoColumnId]);

  const createTask = useCallback(() => {
    if (!draftTitle.trim()) return;
    const newTask: Task = {
      id: `task-${Date.now()}`,
      title: draftTitle.trim(),
      priority: draftPriority,
      assignee: '',
      column: toDoColumnId,
    };
    setTasks((current) => [...current, newTask]);
    taskUpdate({ action: 'create', taskId: newTask.id, data: { column: newTask.column } });
    setDraftTitle('');
    setDraftPriority('medium');
    setNewTaskColumn(null);
  }, [draftPriority, draftTitle, taskUpdate, toDoColumnId]);

  const saveTitle = useCallback((taskId: string) => {
    const nextTitle = editingTitle.trim();
    if (!nextTitle) return;
    const task = getTaskById(taskId);
    if (!task) return;
    setTasks((current) => current.map((item) => (item.id === taskId ? { ...item, title: nextTitle } : item)));
    taskUpdate({ action: 'edit', taskId, data: { column: task.column, title: nextTitle } as unknown as ActionTaskUpdatePayload['data'] });
    setEditingTaskId(null);
    setEditingTitle('');
  }, [editingTitle, getTaskById, taskUpdate]);

  useEffect(() => {
    if (editingTaskId && !editingTitle) {
      const task = tasks.find((item) => item.id === editingTaskId);
      if (task) setEditingTitle(task.title);
    }
  }, [editingTaskId, editingTitle, tasks]);

  useEffect(() => {
    if (newTaskColumn && !columnOrder.some((column) => (column.id ?? '') === newTaskColumn)) {
      setNewTaskColumn(null);
    }
  }, [newTaskColumn, columnOrder]);

  return { taskUpdate, taskChanged, columnOrder, tasks, totalTasks, completedTasks, newTaskColumn, setNewTaskColumn, draftTitle, setDraftTitle, draftPriority, setDraftPriority, createTask, moveTask, editingTaskId, setEditingTaskId, editingTitle, setEditingTitle, saveTitle, applyStreamEvent, handledStreamActions, lastStreamRevision };
}
}

export default function Component(props: Props) {
  const state = useComponent(props);

  const safeColumnStats = Array.isArray(state.columnOrder) ? state.columnOrder : [];
  const columnStats = safeColumnStats.map((column) => ({
    ...column,
    tasks: (Array.isArray(state.tasks) ? state.tasks : []).filter((task) => task.column === column.id),
  }));

  return (
    <Container maxWidth="full" padding={24}>
      <Stack gap={24}>
        <Card padding={16} radius="lg">
          <Stack gap={12}>
            <Row align="center" justify="between" wrap>
              <Heading level={2}>Kanban Board</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {state.totalTasks} total · {state.completedTasks} completed
              </Text>
            </Row>
          </Stack>
