// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}

function useComponent(props: Props) {
  const [query, setQuery] = useState('');
  const [selectedKey, setSelectedKey] = useState<string>('');

  const categoryColors = useMemo(() => ({
    'alkali-metal': 'var(--ggui-color-error-100, #fee2e2)',
    'alkaline-earth-metal': 'var(--ggui-color-warning-100, #fef3c7)',
    'transition-metal': 'var(--ggui-color-primary-100, #e0f2fe)',
    'post-transition-metal': 'var(--ggui-color-info-100, #cffafe)',
    'metalloid': 'var(--ggui-color-success-100, #dcfce7)',
    'nonmetal': 'var(--ggui-color-primary-50, #f0f9ff)',
    'halogen': 'var(--ggui-color-warning-50, #fffbeb)',
    'noble-gas': 'var(--ggui-color-container, #ede9fe)',
    'lanthanide': 'var(--ggui-color-success-50, #f0fdf4)',
    'actinide': 'var(--ggui-color-error-50, #fef2f2)',
    'unknown': 'var(--ggui-color-surfaceVariant, #f4f4f5)',
  }), []);

  const normalizedElements = useMemo(() => {
    const safeElements = Array.isArray(props.elements) ? props.elements : [];
    return safeElements.map((element, index) => ({
      ...element,
      atomicNumber: element.atomicNumber ?? index + 1,
      symbol: element.symbol ?? '',
      name: element.name ?? '',
      atomicWeight: element.atomicWeight ?? 0,
      category: element.category ?? 'unknown',
      row: element.row ?? 1,
      col: element.col ?? 1,
    }));
  }, [props.elements]);

  const filteredElements = useMemo(() => {
    const q = query.trim().toLowerCase();
    return normalizedElements.filter((element) => {
      if (!q) {
        return true;
      }
      return element.name.toLowerCase().includes(q) || element.symbol.toLowerCase().includes(q);
    });
  }, [normalizedElements, query]);

  const categoryCounts = useMemo(() => {
    const counts = new Map<string, number>();
    normalizedElements.forEach((element) => {
      counts.set(element.category, (counts.get(element.category) ?? 0) + 1);
    });
    return counts;
  }, [normalizedElements]);

  const selectedElement = useMemo(() => {
    if (!selectedKey) {
      return null;
    }
    return normalizedElements.find((element) => `${element.atomicNumber}` === selectedKey) ?? null;
  }, [normalizedElements, selectedKey]);

  const legendItems = useMemo(() => {
    const categories = Array.from(new Set(normalizedElements.map((element) => element.category))).sort();
    return categories.map((category) => ({
      category,
      count: categoryCounts.get(category) ?? 0,
      color: categoryColors[category as keyof typeof categoryColors] ?? 'var(--ggui-color-surfaceVariant, #f4f4f5)',
    }));
  }, [categoryColors, categoryCounts, normalizedElements]);

  const selectElement = useCallback((atomicNumber: number) => {
    setSelectedKey(String(atomicNumber));
  }, []);

  const clearFilters = useCallback(() => {
    setQuery('');
    setSelectedKey('');
  }, []);

  return {
    query,
    setQuery,
    selectedKey,
    selectedElement,
    selectElement,
    clearFilters,
    categoryColors,
    normalizedElements,
    filteredElements,
    legendItems,
  };
}
}

