}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };

function useComponent(props: Props) {
  const product = props.product ?? {};
  const productId = product.id ?? '';
  const productName = product.name ?? 'Product';
  const price = typeof product.price === 'number' ? product.price : 0;
  const currency = product.currency ?? 'USD';
  const rating = Math.max(0, Math.min(5, Math.round(typeof product.rating === 'number' ? product.rating : 0)));
  const reviewCount = typeof product.reviewCount === 'number' ? product.reviewCount : 0;
  const stock = Math.max(0, Math.floor(typeof product.stock === 'number' ? product.stock : 0));
  const description = product.description ?? '';
  const specifications = Array.isArray(product.specifications) ? product.specifications : [];
  const reviews = Array.isArray(product.reviews) ? product.reviews : [];
  const onAddToCart = (props as Props & { onAddToCart?: (payload: ActionAddToCartPayload) => void }).onAddToCart;

  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const formatPrice = useCallback((value: number) => {
    try {
      return new Intl.NumberFormat(undefined, { style: 'currency', currency }).format(value);
    } catch {
      return `${currency} ${value.toFixed(2)}`.trim();
    }
  }, [currency]);

  const clampQuantity = useCallback((value: number) => {
    const max = stock > 0 ? stock : 1;
    return Math.min(max, Math.max(1, value));
  }, [stock]);

  const incrementQuantity = useCallback(() => {
    setQuantity((current) => clampQuantity(current + 1));
  }, [clampQuantity]);

  const decrementQuantity = useCallback(() => {
    setQuantity((current) => clampQuantity(current - 1));
  }, [clampQuantity]);

  const handleAddToCart = useCallback(() => {
    if (!productId || stock <= 0 || typeof onAddToCart !== 'function') return;
    onAddToCart({ productId, quantity: clampQuantity(quantity) });
  }, [clampQuantity, onAddToCart, מוצרId, quantity, stock]);

  const canAddToCart = stock > 0 && Boolean(productId);
  const displayQuantity = clampQuantity(quantity);

  return {
    productId,
    productName,
    price,
    currency,
    rating,
    reviewCount,
    stock,
    description,
    specifications,
    reviews,
    quantity: displayQuantity,
    activeTab,
    setActiveTab,
    incrementQuantity,
    decrementQuantity,
    handleAddToCart,
    canAddToCart,
    formatPrice,
  };
}
}


