// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };

function useComponent(props: Props) {
  const [draft, setDraft] = useState('');
  const [sentMessages, setSentMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>(props.messages ?? []);
  const [streamMessages, setStreamMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>([]);
  const [typingStates, setTypingStates] = useState<Array<{ sender?: string; active?: boolean }>>([]);
  const sendMessage = useAction('sendMessage');
  const streamMessagesEvent = useStream<StreamMessage>('message');
  const streamTypingEvent = useStream<StreamTyping>('typing');

  React.useEffect(() => {
    setSentMessages(props.messages ?? []);
  }, [props.messages]);

  React.useEffect(() => {
    if (streamMessagesEvent.latest && streamMessagesEvent.latest.text) {
      setStreamMessages((current) => [...current, streamMessagesEvent.latest]);
    }
  }, [streamMessagesEvent.latest]);

  React.useEffect(() => {
    if (!streamTypingEvent.latest || !streamTypingEvent.latest.sender) return;
    setTypingStates((current) => {
      const next = current.filter((item) => item.sender !== streamTypingEvent.latest.sender);
      return streamTypingEvent.latest.active ? [...next, streamTypingEvent.latest] : next;
    });
  }, [streamTypingEvent.latest]);

  const handleDraftChange = useCallback((value: string) => {
    setDraft(value);
  }, []);

  const handleSend = useCallback(() => {
    const text = draft.trim();
    if (!text) return;
    const timestamp = new Date().toISOString();
    sendMessage({ text, timestamp });
    setSentMessages((current) => [...current, { sender: props.currentUser, text, timestamp }]);
    setDraft('');
  }, [draft, props.currentUser, sendMessage]);

  const handleKeyDown = useCallback((event: React.KeyboardEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    if (event.key === 'Enter' && !event.shiftKey) {
      event.preventDefault();
      handleSend();
    }
  }, [handleSend]);

  const mergedMessages = [...sentMessages, ...streamMessages];
  const participantBadgeLabel = `${props.participantCount}`;
  const activeTypingSenders = typingStates.filter((item) => item.active && item.sender).map((item) => item.sender as string);
  const typingSender = activeTypingSenders[activeTypingSenders.length - 1];

  return {
    draft,
    handleDraftChange,
    handleSend,
    handleKeyDown,
    mergedMessages,
    isTyping: activeTypingSenders.length > 0,
    typingSender,
    participantBadgeLabel,
  };
}




export default function Component(props: Props) {
  const state = useComponent(props);
  const bottomRef = useRef<HTMLDivElement | null>(null);

  React.useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [state.mergedMessages.length, state.isTyping]);

  const groupedMessages = state.mergedMessages.reduce<Array<Array<{ sender?: string; text?: string; timestamp?: string }>>>((groups, current) => {
    const previousGroup = groups[groups.length - 1];
    const lastMessage = previousGroup ? previousGroup[previousGroup.length - 1] : undefined;
    if (lastMessage && lastMessage.sender === current.sender) {
      previousGroup.push(current);
    } else {
      groups.push([current]);
    }
    return groups;
  }, []);

  return (
    <Container maxWidth="lg" padding={16}>
      <Card padding={0} shadow="md" radius="lg">
        <Stack gap={0}>
          <Box padding={16} background="var(--ggui-color-container, #ede9fe)">
            <Stack gap={12}>
              <Row align="center" justify="between" style={{ gap: 'var(--ggui-spacing-4, 16px)' }}>
                <Stack gap={4}>
                  <Heading level={3} color="var(--ggui-color-onContainer, #4c1d95)">{props.title}</Heading>
                  <Text variant="caption" color="var(--ggui-color-onContainer, #4c1d95)">
                    Real-time messaging
                  </Text>
                </Stack>
                <Row align="center" style={{ gap: 'var(--ggui-spacing-2, 8px)' }}>
                  <Badge variant="primary" size="sm">{state.participantBadgeLabel}</Badge>
                  <Text variant="caption" color="var(--ggui-color-onContainer, #4c1d95)">Participants</Text>
                </Row>
              </Row>
              {state.isTyping ? (
                <Alert variant="info">
                  <Text variant="bodySmall" color="var(--ggui-color-info-800, #155e75)">
                    {state.typingSender ? `${state.typingSender} is typing...` : 'Someone is typing...'}
                  </Text>
                </Alert>
              ) : null}
            </Stack>
          </Box>

          <Box padding={16} background="var(--ggui-color-surface, #fafafa)">
            <Stack gap={12}>
              <Box
                style={{
                  maxHeight: '60vh',
                  overflowY: 'auto',
                  paddingRight: 'var(--ggui-spacing-2, 8px)',
                }}
              >
                <Stack gap={12}>
                  {groupedMessages.map((group, groupIndex) => {
                    const first = group[0];
                    const mine = first?.sender === props.currentUser;
                    return (
                      <Stack key={`${first?.timestamp ?? groupIndex}-${groupIndex}`} gap={8} align={mine ? 'end' : 'start'}>
                        <Box
                          padding={0}
                          style={{
                            alignSelf: mine ? 'flex-end' : 'flex-start',
                            maxWidth: '80%',
                          }}
                        >
                          <Stack gap={8}>
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                              {first?.sender ?? 'Unknown'}
                            </Text>
                            <Stack gap={8}>
                              {group.map((item, itemIndex) => {
                                const isMine = item.sender === props.currentUser;
                                return (
                                  <Box
                                    key={`${item.timestamp ?? groupIndex}-${itemIndex}`}
                                    padding={12}
                                    borderRadius="var(--ggui-shape-radius-lg, 12px)"
                                    background={
                                      isMine
                                        ? 'var(--ggui-color-primary-600, #0284c7)'
                                        : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                                    }
                                  >
                                    <Stack gap={4}>
                                      <Text
                                        variant="body"
                                        color={
                                          isMine
                                            ? 'var(--ggui-color-surface, #fafafa)'
                                            : 'var(--ggui-color-onSurface, #18181b)'
                                        }
                                      >
                                        {item.text ?? ''}
                                      </Text>
                                      <Text
                                        variant="caption"
                                        color={
                                          isMine
                                            ? 'var(--ggui-color-primary-100, #e0f2fe)'
                                            : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                                        }
                                      >
                                        {item.timestamp ? new Date(item.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : ''}
                                      </Text>
                                    </Stack>
                                  </Box>
                                );
                              })}
                            </Stack>
                          </Stack>
                        </Box>
                      </Stack>
                    );
                  })}
                  <div ref={bottomRef} />
                </Stack>
              </Box>

              <Divider margin={0} />

              <Row align="end" style={{ gap: 'var(--ggui-spacing-2, 8px)' }}>
                <Box style={{ flex: 1 }}>
                  <TextArea
                    label="Message"
                    value={state.draft}
                    onChange={state.handleDraftChange}
                    placeholder="Type your message..."
                    rows={3}
                    onKeyDown={state.handleKeyDown as unknown as React.KeyboardEventHandler<HTMLTextAreaElement>}
                  />
                </Box>
                <Button variant="primary" onClick={state.handleSend} disabled={!state.draft.trim()}>
                  Send
                </Button>
              </Row>
            </Stack>
          </Box>
        </Stack>
      </Card>
    </Container>
  );
}

