import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };

function useComponent(props: Props) {
  const [stocks, setStocks] = useState(props.stocks ?? []);
  const [lastUpdated, setLastUpdated] = useState(new Date());
  const [flashSymbols, setFlashSymbols] = useState<string[]>([]);
  const [marketOpenState, setMarketOpenState] = useState<'open' | 'closed' | 'pre-market' | 'after-hours' | null>(null);
  const flashTimersRef = useRef<Record<string, number>>({});
  const [lastReceivedUpdate, setLastReceivedUpdate] = useState<StreamPriceUpdate | null>(null);
  const [lastReceivedMarketStatus, setLastReceivedMarketStatus] = useState<StreamMarketStatus | null>(null);

  const formatTime = useCallback((date: Date) => {
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
  }, []);

  const formatPrice = useCallback((value?: number) => {
    return (value ?? 0).toFixed(2);
  }, []);

  const formatSignedNumber = useCallback((value?: number) => {
    const safe = value ?? 0;
    const sign = safe > 0 ? '+' : '';
    return `${sign}${safe.toFixed(2)}`;
  }, []);

  const syncStockUpdate = useCallback((update?: StreamPriceUpdate) => {
    if (!update?.symbol) return;
    setStocks((current) => {
      let changed = false;
      const next = current.map((stock) => {
        if (stock.symbol !== update.symbol) return stock;
        changed = true;
        return { ...stock, ...update };
      });
      return changed ? next : current;
    });
    setFlashSymbols((current) => Array.from(new Set([...current, update.symbol as string])));
    setLastUpdated(new Date());
    if (flashTimersRef.current[update.symbol]) {
      window.clearTimeout(flashTimersRef.current[update.symbol]);
    }
    flashTimersRef.current[update.symbol] = window.setTimeout(() => {
      setFlashSymbols((current) => current.filter((symbol) => symbol !== update.symbol));
      delete flashTimersRef.current[update.symbol];
    }, 700);
  }, []);

  React.useEffect(() => {
    setStocks(props.stocks ?? []);
  }, [props.stocks]);

  React.useEffect(() => {
    if (lastReceivedUpdate?.symbol) {
      syncStockUpdate(lastReceivedUpdate);
    }
  }, [lastReceivedUpdate, syncStockUpdate]);

  React.useEffect(() => {
    if (lastReceivedMarketStatus?.status) {
      setMarketOpenState(lastReceivedMarketStatus.status);
      setLastUpdated(new Date());
    }
  }, [lastReceivedMarketStatus]);

  React.useEffect(() => {
    const timer = window.setInterval(() => setLastUpdated(new Date()), 1000);
    return () => window.clearInterval(timer);
  }, []);

  return {
    stocks,
    lastUpdated,
    flashSymbols,
    marketOpenState,
    formatTime,
    formatPrice,
    formatSignedNumber,
    setLastReceivedUpdate,
    setLastReceivedMarketStatus,
  };
}
}

export default function Component(props: Props) {
  const state = useComponent(props);
  const marketLabel = state.marketOpenState ? `Market ${state.marketOpenState}` : 'Market Watch';

  const gridTemplateColumns = 'repeat(3, minmax(0, 1fr))';

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Card shadow="sm" radius="lg" padding="var(--ggui-spacing-4, 16px)">
          <Stack gap="var(--ggui-spacing-2, 8px)" direction="horizontal" align="center" justify="between" wrap>
            <Stack gap="var(--ggui-spacing-1, 4px)">
              <Heading level={1}>Market Watch</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Live stock prices and stream updates
              </Text>
            </Stack>
            <Stack gap="var(--ggui-spacing-1, 4px)" align="end">
              <Badge variant={state.marketOpenState === 'closed' ? 'warning' : 'success'} size="sm">
                {marketLabel}
              </Badge>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Last Updated: {state.formatTime(state.lastUpdated)}
              </Text>
            </Stack>
          </Stack>
        </Card>

        <Box
          style={{
            display: 'grid',
            gridTemplateColumns,
            gap: 'var(--ggui-spacing-4, 16px)',
          }}
        >
          {state.stocks.map((stock) => {
            const positive = (stock.change ?? 0) >= 0;
            const isFlashing = state.flashSymbols.includes(stock.symbol ?? '');
            const borderColor = positive ? 'var(--ggui-color-success, #16a34a)' : 'var(--ggui-color-error, #dc2626)';
            const textColor = positive ? 'var(--ggui-color-success, #16a34a)' : 'var(--ggui-color-error, #dc2626)';
            return (
              <Card
                key={stock.symbol}
                shadow="sm"
                radius="lg"
                padding="var(--ggui-spacing-4, 16px)"
                border
                style={{
                  borderColor,
                  boxShadow: isFlashing ? 'var(--ggui-shape-shadow-lg, 0 10px 15px -3px rgba(0,0,0,0.1))' : undefined,
                  animation: isFlashing ? 'ggui-fadeIn 200ms ease-out' : undefined,
                  transition: 'box-shadow 200ms ease-in-out, border-color 200ms ease-in-out, background-color 200ms ease-in-out',
                  backgroundColor: isFlashing ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-surface, #fafafa)',
                }}
              >
                <Stack gap="var(--ggui-spacing-2, 8px)">
                  <Stack gap="var(--ggui-spacing-1, 4px)">
                    <Heading level={2} color={textColor}>
                      {stock.symbol}
                    </Heading>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {stock.name}
                    </Text>
                  </Stack>

                  <Divider margin="var(--ggui-spacing-2, 8px)" color="var(--ggui-color-outlineVariant, #e4e4e7)" />
                  <Stack gap="var(--ggui-spacing-1, 4px)">
                    <Text variant="bodyLarge" weight="bold">
                      ${state.formatPrice(stock.price)}
                    </Text>
                    <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
                      <Text variant="label" color={textColor}>
                        {state.formatSignedNumber(stock.change)}
                      </Text>
                      <Text variant="label" color={textColor}>
                        <span aria-hidden="true">{positive ? '▲' : '▼'}</span> {state.formatPrice(stock.changePercent)}%
                      </Text>
                    </Stack>
                  </Stack>
                </Stack>
              </Card>
            );
          })}
        </Box>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };

function useComponent(props: Props) {
  const complete = useCallback((payload: ActionCompletePayload) => {
    void payload;
  }, []);

  const avatarFallback = props.avatarOptions[0] ?? '🙂';
  const roleFallback = props.roleOptions[0] ?? 'Other';
  const [step, setStep] = useState(1);
  const [name, setName] = useState(props.initialProfile.name ?? '');
  const [email, setEmail] = useState(props.initialProfile.email ?? '');
  const [avatar, setAvatar] = useState(props.initialProfile.avatar ?? avatarFallback);
  const [role, setRole] = useState(props.initialProfile.role ?? roleFallback);
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile.theme ?? 'light');

  const emailIsValid = /^\S+@\S+\.\S+$/.test(email);
  const canGoNext = step === 1 ? Boolean(name.trim()) && emailIsValid && Boolean(avatar) : step === 2 ? Boolean(role) : false;

  const goNext = useCallback(() => {
    setStep((current) => Math.min(3, current + 1));
  }, []);

  const goBack = useCallback(() => {
    setStep((current) => Math.max(1, current - 1));
  }, []);

  const completeSetup = useCallback(() => {
    complete({ name: name.trim(), email: email.trim(), avatar, role, emailNotifications, theme });
  }, [avatar, complete, email, emailNotifications, name, role, theme]);

  return {
    complete,
    step,
    setStep,
    name,
    setName,
    email,
    setEmail,
    avatar,
    setAvatar,
    role,
    setRole,
    emailNotifications,
    setEmailNotifications,
    theme,
    setTheme,
    emailIsValid,
    canGoNext,
    goNext,
    goBack,
    completeSetup,
  };
}
}

export default function Component(props: Props) {
  const state = useComponent(props);

  const stepProgress = ((state.step - 1) / 2) * 100;

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={24}>
        <Card padding={24} shadow="sm">
          <Stack gap={16}>
            <Row align="center" justify="between">
              <Heading level={2}>Onboarding Wizard</Heading>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Step {state.step}/3
              </Text>
            </Row>
            <Progress value={stepProgress} max={100} size="sm" showLabel />
          </Stack>
        </Card>

        <Card padding={24} shadow="sm">
          <Box
            style={{
              transition: 'opacity 200ms ease, transform 200ms ease',
              animation: 'ggui-fadeIn 200ms ease-out both',
            }}
          >
            <Stack gap={24}>
              {state.step === 1 && (
                <Stack gap={16}>
                  <Heading level={3}>Profile Setup</Heading>
                  <FormField label="Name" required>
                    <Input label="Name" value={state.name} onChange={state.setName} placeholder="Enter your name" />
                  </FormField>
                  <FormField
                    label="Email"
                    required
                    error={state.email && !state.emailIsValid ? 'Enter a valid email address.' : undefined}
                  >
                    <Input label="Email" value={state.email} onChange={state.setEmail} type="email" placeholder="you@example.com" />
                  </FormField>
                  <Box>
                    <Text variant="label">Avatar</Text>
                    <Stack direction="horizontal" gap={8} wrap>
                      {props.avatarOptions.map((option) => (
                        <Button
                          key={option}
                          variant={state.avatar === option ? 'primary' : 'secondary'}
                          size="sm"
                          onClick={() => state.setAvatar(option)}
                        >
                          {option}
                        </Button>
                      ))}
                    </Stack>
                  </Box>
                </Stack>
              )}

              {state.step === 2 && (
                <Stack gap={16}>
                  <Heading level={3}>Preferences</Heading>
                  <Select
                    label="Role"
                    value={state.role}
                    onChange={state.setRole}
                    options={props.roleOptions.map((option) => ({ value: option, label: option }))}
                  />
                  <Toggle
                    label="Email notifications"
                    checked={state.emailNotifications}
                    onChange={state.setEmailNotifications}
                  />
                  <Toggle
                    label="Theme preference"
                    checked={state.theme === 'dark'}
                    onChange={(checked) => state.setTheme(checked ? 'dark' : 'light')}
                  />
                </Stack>
              )}

              {state.step === 3 && (
                <Stack gap={16}>
                  <Heading level={3}>Review &amp; Confirm</Heading>
                  <Card padding={16} shadow="none" border radius="md">
                    <Stack gap={8}>
                      <Text><strong>Name:</strong> {state.name}</Text>
                      <Text><strong>Email:</strong> {state.email}</Text>
                      <Text><strong>Avatar:</strong> {state.avatar}</Text>
                      <Text><strong>Role:</strong> {state.role}</Text>
                      <Text><strong>Email notifications:</strong> {state.emailNotifications ? 'On' : 'Off'}</Text>
                      <Text><strong>Theme:</strong> {state.theme}</Text>
                    </Stack>
                  </Card>
                </Stack>
              )}

              <Divider />

              <Row justify="between" align="center">
                <Button variant="ghost" onClick={state.goBack} disabled={state.step === 1}>Go Back</Button>
                <Spacer size="flex" />
                {state.step < 3 ? (
                  <Button variant="primary" onClick={state.goNext} disabled={!state.canGoNext}>Next</Button>
                ) : (
                  <Button variant="primary" onClick={state.completeSetup}>Complete Setup</Button>
                )}
              </Row>
            </Stack>
          </Box>
        </Card>
      </Stack>
    </Container>
  );
}
